SELECT [Model Item Variable Group].*
FROM [Model Item Variable Group]
WHERE ((([Model Item Variable Group].[Model Item No_])="7FARIA01/LEA" Or ([Model Item Variable Group].[Model Item No_])="7FWOSUONO01/LEA" Or ([Model Item Variable Group].[Model Item No_])="YLE14/TEXTURED" Or ([Model Item Variable Group].[Model Item No_])="DLY32/NET" Or ([Model Item Variable Group].[Model Item No_])="JNE04/CROSTA-VIT" Or ([Model Item Variable Group].[Model Item No_])="7FMURRAY01/LEA" Or ([Model Item Variable Group].[Model Item No_])="7SWOBOWLING/LEA" Or ([Model Item Variable Group].[Model Item No_])="8SMADISON01/MES" Or ([Model Item Variable Group].[Model Item No_])="8SMASTER01/LEA"));

